/// A custom loading indicator widget, and its modal dialog function and stack container.
///
/// {@category Widgets}
library;

// Flutter imports:
import 'package:flutter/material.dart';

// Package imports:
import 'package:flutter_hooks/flutter_hooks.dart';

// Project imports:
import 'package:baseball_detector_flutter/views/routers/app_router.dart';
import 'package:baseball_detector_flutter/views/routers/navigation_state_extension.dart';
import 'package:baseball_detector_flutter/views/themes/color_manager.dart';

/// A custom loading indicator widget.
class CustomLoadingIndicator extends StatelessWidget {
  final double? progress;

  const CustomLoadingIndicator({super.key, this.progress});

  @override
  Widget build(BuildContext context) {
    final loadingIndicator = SizedBox(
      width: 32,
      height: 32,
      child: TweenAnimationBuilder(
        tween: Tween(begin: 0.0, end: progress ?? 0.0),
        duration: const Duration(milliseconds: 250),
        curve: Curves.easeOut,
        builder: (context, value, _) => RepaintBoundary(
          // RepaintBoundaryを追加してアニメーションを最適化
          child: CircularProgressIndicator(
            color: ColorManager.blueCrayola,
            strokeWidth: 2.5,
            value: progress != null && progress != 0 ? value : null,
          ),
        ),
      ),
    );

    // Apply clamping to filter invalid values
    // It may take a negative value when an error occurs or the function is
    // canceled. This is for convenience, although filtering should be done on
    // the caller side.
    final text =
        progress != null ? '${(progress! * 100).toInt().clamp(0, 100)}%' : null;
    final textIsNotEmpty = text?.isNotEmpty ?? false;
    return Center(
      child: Container(
        width: 100,
        height: 100,
        padding: const EdgeInsets.all(10),
        decoration: BoxDecoration(
          borderRadius: const BorderRadius.all(Radius.circular(10)),
          color: ColorManager.blueCrayola.withValues(alpha: 0.5),
        ),
        child: Column(
          mainAxisAlignment: MainAxisAlignment.center,
          children: [
            loadingIndicator,
            Visibility(
              visible: textIsNotEmpty,
              child: Padding(
                padding: const EdgeInsets.only(top: 8),
                child: Text(
                  text ?? '',
                  overflow: TextOverflow.ellipsis,
                  textAlign: TextAlign.center,
                  style: TextStyle(
                    color: Colors.white,
                  ),
                ),
              ),
            ),
          ],
        ),
      ),
    );
  }
}

/// A modal dialog function for CustomLoadingIndicator.
Route showLoadingDialog({
  required BuildContext context,
  ValueNotifier<double>? progress,
  bool visible = true,
  bool canPop = false,
  void Function()? onPopInvoked,
}) {
  late final Route route;
  showGeneralDialog(
    context: context,
    barrierDismissible: false,
    transitionDuration: const Duration(milliseconds: 150),
    barrierColor:
        visible ? Colors.black.withValues(alpha: 0.5) : Colors.transparent,
    pageBuilder: (BuildContext context, Animation animation,
        Animation secondaryAnimation) {
      return PopScope(
        canPop: canPop,
        onPopInvokedWithResult:
            onPopInvoked != null ? (_, __) => onPopInvoked() : null,
        child: visible
            ? Material(
                color: Colors.transparent,
                child: HookBuilder(builder: (context) {
                  useListenable(progress);
                  return CustomLoadingIndicator(progress: progress?.value);
                }),
              )
            : const SizedBox.shrink(),
      );
    },
    routeSettings: const RouteSettings(name: AppRouter.loadingDialog),
  );

  route = Navigator.of(context, rootNavigator: true).currentRoute!;
  return route;
}

/// Pops the loading dialog specified by [dialog] and returns true if successful.
/// If [route] is not the current route, waits until it becomes the current route.
/// Returns [false] if [route] does not or no longer exists in Navigator.
Future<bool> popLoadingDialog({
  required BuildContext context,
  required Route dialog,
}) async {
  bool? result = _tryToPopLoadingDialog(context: context, dialog: dialog);
  if (result != null) {
    return result;
  }

  await for (final _ in appRouterStreamer.stream) {
    result = _tryToPopLoadingDialog(context: context, dialog: dialog);
    if (result != null) {
      return result;
    }
  }

  throw Exception('unreachable');
}

bool? _tryToPopLoadingDialog({
  required BuildContext context,
  required Route dialog,
}) {
  if (dialog.isCurrent) {
    Navigator.of(context, rootNavigator: true).pop();
    return true;
  }
  if (!dialog.isActive) {
    return false;
  }
  return null;
}

