    38→import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/recording/hooks/use_accelerometer_orientation.dart';
    39→import 'package:baseball_detector_flutter/views/pages/home/settings/hooks/use_tutorial_video.dart';
    40→import 'package:baseball_detector_flutter/views/themes/color_manager.dart';
    41→
    42→class RecordingPage extends HookConsumerWidget {
    43→  const RecordingPage({
    44→    required this.sessionId,
    45→    required this.sessionCreatedAt,
    46→    required this.teamId,
    47→    super.key,
    48→  });
    49→
    50→  final String sessionId;
    51→  final DateTime sessionCreatedAt;
    52→  final String teamId;
    53→
    54→  @override
    55→  Widget build(BuildContext context, WidgetRef ref) {
    56→    final previewKey = useMemoized(() => ValueKey('camera_preview_$sessionId'));
    57→    final isRecording = useValueNotifier(false);
    58→    final recordingTimerCount = useValueNotifier(0);
    59→    final selected = useValueNotifier<CameraConfigurationDisplayType?>(null);
    60→    final isLatestAnalysisResultCardVisible = useValueNotifier(false);
    61→    final currentOrientation =
    62→        useValueNotifier(NativeDeviceOrientation.unknown);
    63→    final notifier = ref.watch(cameraControllerProvider.notifier);
    64→    final analysisType = ref.watch(
    65→      cameraControllerProvider.select((value) => value.analysisType),
    66→    );
    67→    final isSingleTeam = useSingleTeamCheck();
    68→
    69→    // Coach mark keys
    70→    final recordButtonKey = useMemoized(() => GlobalKey());
    71→    final analysisModeKey = useMemoized(() => GlobalKey());
    72→    final focusButtonKey = useMemoized(() => GlobalKey());
    73→    final configurationKey = useMemoized(() => GlobalKey());
    74→
    75→    // Camera and session related states
    76→    final cameraId = useRef<int?>(null);
    77→    final subscription = useRef<StreamSubscription?>(null);
    78→    final recordingTimer = useRef<Timer?>(null);
    79→
    80→    // cameraController を watch しないと、initializeCamera で初期化された CameraController が破棄される (watch している Widget がなくなるため)
    81→    // 破棄されると ControlPanel などで参照している値が null になってしまう。
    82→    ref.watch(cameraControllerProvider.select((value) => value.cameraMode));
    83→
    84→    // Tutorial state
    85→    final tutorialState = ref.watch(recordingTutorialProvider);
    86→    final tutorialNotifier = ref.watch(recordingTutorialProvider.notifier);
    87→    final isShowingCoachMarks = useValueNotifier(false);
    88→
    89→    final launchTutorialVideoUrl = useTutorialVideo(isForRecording: true);
    90→
    91→    // Use accelerometer orientation detection hook
    92→    useAccelerometerOrientation(
    93→      config: AccelerometerOrientationConfig(
    94→        showMismatchDialog: !isShowingCoachMarks.value,
    95→      ),
    96→    );
    97→
    98→    useEffect(() {
    99→      if (!isSingleTeam) return null;
   100→      final fallback = analysisType.fallbackForSingleTeam();
   101→      if (analysisType != fallback) {
   102→        Future.microtask(() async {
   103→          await notifier.setAnalysisType(fallback);
   104→        });
   105→      }
   106→      return null;
   107→    }, [isSingleTeam, analysisType, notifier]);
   108→
   109→    // Camera initialization function
   110→    Future<
   111→        ({
   112→          bool recordingDirectoryInitialized,
   113→          bool cameraIdInitialized,
   114→        })> initializeCamera() async {
   115→      final recordingDirectory = await notifier.initializeRecordingDirectory(
   116→        sessionId,
   117→        sessionCreatedAt,
   118→      );
   119→
   120→      cameraId.value = await notifier.configureSession(
   121→        platform.isIos
   122→            ? () => tapRecordingButton(
   123→                  context: context,
   124→                  ref: ref,
   125→                  isRecording: isRecording,
   126→                  currentOrientation: currentOrientation,
   127→                  recordingTimerCount: recordingTimerCount,
   128→                  recordingTimer: recordingTimer,
   129→                )
   130→            : null,
   131→      );
   132→      return (
   133→        recordingDirectoryInitialized: recordingDirectory != null,
   134→        cameraIdInitialized: cameraId.value != null,
   135→      );
   136→    }
   137→
   138→    final cameraInitialization = useFuture(useMemoized(initializeCamera));
   139→
   140→    // Show coach marks after camera initialization
   141→    useEffect(() {
   142→      if (cameraInitialization.hasData &&
   143→          cameraInitialization.data!.cameraIdInitialized &&
   144→          !tutorialState.isLoading &&
   145→          !tutorialState.hasShownTutorial) {
   146→        WidgetsBinding.instance.addPostFrameCallback((_) async {
   147→          isShowingCoachMarks.value = true;
   148→          RecordingCoachMarks.show(
   149→            context: context,
   150→            targets: RecordingCoachMarkTargets(
   151→              recordButtonKey: recordButtonKey,
   152→              analysisModeKey: analysisModeKey,
   153→              focusButtonKey: focusButtonKey,
   154→            ),
   155→            onFinish: () async {
   156→              isShowingCoachMarks.value = false;
   157→              await tutorialNotifier.markTutorialAsShown();
   158→            },
   159→            launchTutorialVideoUrl: launchTutorialVideoUrl,
   160→          );
   161→        });
   162→      }
   163→      return null;
   164→    }, [cameraInitialization.hasData, tutorialState]);
   165→
   166→    // Acceleration sensor subscription and resource management
   167→    useEffectOnce(() {
   168→      // Subscribe to acceleration sensor events
   169→      subscription.value = accelerometerEventStream().listen(
   170→        AccelerationController.getSingletonObject().handle,
   171→        onError: AccelerationController.getSingletonObject().handleError,
   172→        cancelOnError: true,
   173→      );
   174→
   175→      // Screen settings
   176→      WakelockPlus.enable();
   177→      SystemChrome.setEnabledSystemUIMode(SystemUiMode.immersiveSticky);
   178→
   179→      // Cleanup function
   180→      return () {
   181→        recordingTimer.value?.cancel();
   182→        recordingTimer.value = null;
   183→        isRecording.value = false;
   184→
   185→        // Unsubscribe from acceleration sensor
   186→        if (subscription.value != null) {
   187→          subscription.value!.cancel();
   188→          subscription.value = null;
   189→        }
   190→
   191→        // Release camera resources
   192→        if (cameraId.value != null) {
   193→          // ここで ref.read(cameraControllerProvider.notifier) をすでに破棄された
   194→          // notifier を使用しているためエラーが発生する。
   195→          notifier.closeSession();
   196→        }
   197→
   198→        // Restore screen settings
   199→        SystemChrome.setEnabledSystemUIMode(SystemUiMode.edgeToEdge);
   200→        ScreenOrientation.setDefault();
   201→        WakelockPlus.disable();
   202→      };
   203→    });
   204→
   205→    // Build UI based on initialization state
   206→    if (!cameraInitialization.hasData) return const CustomLoadingIndicator();
   207→
   208→    // Recording directory initialization failed screen
   209→    if (!cameraInitialization.data!.recordingDirectoryInitialized) {
   210→      return _buildRecordingDirectoryInitializationFailedUI(context);
   211→    }
   212→
   213→    // Permission denied screen if camera ID is null
   214→    if (!cameraInitialization.data!.cameraIdInitialized) {
   215→      return _buildPermissionDeniedUI(context);
   216→    }
   217→
   218→    // Main UI (preview and controls)
   219→    final previewWidget = _buildCameraPreview(
   220→      context,
   221→      ref,
   222→      previewKey: previewKey,
   223→      cameraId: cameraId,
   224→      recordingTimer: recordingTimer,
   225→      currentOrientation: currentOrientation,
   226→      recordingTimerCount: recordingTimerCount,
   227→      isRecording: isRecording,
   228→      selected: selected,
   229→      isLatestAnalysisResultCardVisible: isLatestAnalysisResultCardVisible,
   230→      recordButtonKey: recordButtonKey,
   231→      analysisModeKey: analysisModeKey,
   232→      focusButtonKey: focusButtonKey,
   233→      configurationKey: configurationKey,
   234→      isShowingCoachMarks: isShowingCoachMarks,
   235→      launchTutorialVideoUrl: launchTutorialVideoUrl,
   236→    );
   237→
   238→    // Add volume key handler based on platform
   239→    return platform.isIos
   240→        ? previewWidget
   241→        : VolumeKeyHandler(
   242→            enable: true,
   243→            onPressed: (VolumeKey volumeKey) {
   244→              _onVolumeKeyPressed(
   245→                context: context,
   246→                ref: ref,
   247→                isRecording: isRecording,
   248→                currentOrientation: currentOrientation,
   249→                recordingTimerCount: recordingTimerCount,
   250→                recordingTimer: recordingTimer,
   251→              );
   252→            },
   253→            child: previewWidget,
   254→          );
   255→  }
   256→
   257→  // UI for when camera permission is denied
   258→  Widget _buildPermissionDeniedUI(BuildContext context) {
