   260→      appBar: CustomAppBar(
   261→        isBackNavigation: true,
   262→        backgroundColor: ColorManager.cameraControlBackground,
   263→      ),
   264→      backgroundColor: Colors.black,
   265→      body: Center(
   266→        child: Container(
   267→          padding: const EdgeInsets.all(10),
   268→          child: Text(
   269→            context.l10n.recording_page__not_permitted,
   270→            style: const TextStyle(color: Colors.white),
   271→          ),
   272→        ),
   273→      ),
   274→    );
   275→  }
   276→
   277→  // UI for when recording directory initialization failed
   278→  Widget _buildRecordingDirectoryInitializationFailedUI(
   279→    BuildContext context,
   280→  ) {
   281→    return Scaffold(
   282→      appBar: CustomAppBar(
   283→        isBackNavigation: true,
   284→        backgroundColor: ColorManager.cameraControlBackground,
   285→      ),
   286→      backgroundColor: Colors.black,
   287→      body: Center(
   288→        child: Container(
   289→          padding: const EdgeInsets.all(10),
   290→          child: Text(
   291→            context
   292→                .l10n.recording_page__recording_directory_initialization_failed,
   293→            style: const TextStyle(color: Colors.white),
   294→          ),
   295→        ),
   296→      ),
   297→    );
   298→  }
   299→
   300→  // Camera preview and control UI
   301→  Widget _buildCameraPreview(
   302→    BuildContext context,
   303→    WidgetRef ref, {
   304→    required ValueKey previewKey,
   305→    required ObjectRef<int?> cameraId,
   306→    required ObjectRef<Timer?> recordingTimer,
   307→    required ValueNotifier<NativeDeviceOrientation> currentOrientation,
   308→    required ValueNotifier<int> recordingTimerCount,
   309→    required ValueNotifier<bool> isRecording,
   310→    required ValueNotifier<CameraConfigurationDisplayType?> selected,
   311→    required ValueNotifier<bool> isLatestAnalysisResultCardVisible,
   312→    required GlobalKey recordButtonKey,
   313→    required GlobalKey analysisModeKey,
   314→    required GlobalKey focusButtonKey,
   315→    required GlobalKey configurationKey,
   316→    required ValueNotifier<bool> isShowingCoachMarks,
   317→    required VoidCallback launchTutorialVideoUrl,
   318→  }) {
   319→    // Don't show preview if camera ID is null
   320→    if (cameraId.value == null) {
   321→      return const SizedBox.shrink();
   322→    }
   323→
   324→    return Stack(
   325→      children: [
   326→        // Camera preview
   327→        SizedBox(
   328→          width: MediaQuery.of(context).size.width,
   329→          height: MediaQuery.of(context).size.height,
   330→          child: FittedBox(
   331→            fit: BoxFit.cover,
   332→            child: CameraPreviewView(
   333→              key: previewKey,
   334→              cameraId: cameraId.value!,
   335→            ),
   336→          ),
   337→        ),
   338→        // Orientation detection and control UI
   339→        _OrientationAbsorber(
   340→          onOrientationChanged: (orientation) {
   341→            currentOrientation.value = orientation;
   342→          },
   343→          child: _TranslucentPointer(
   344→            child: Material(
   345→              color: Colors.transparent,
   346→              child: Column(
   347→                crossAxisAlignment: CrossAxisAlignment.stretch,
   348→                children: [
   349→                  HookBuilder(
   350→                    builder: (context) {
   351→                      final isCoachMarksVisible =
   352→                          useValueListenable(isShowingCoachMarks);
   353→                      // Camera recording UI top section
   354→                      return RecordingAppBar(
   355→                        currentOrientation: currentOrientation,
   356→                        isRecording: isRecording,
   357→                        isLatestAnalysisResultCardVisible:
   358→                            isLatestAnalysisResultCardVisible,
   359→                        recordingTimerCount: recordingTimerCount,
   360→                        selected: selected,
   361→                        analysisModeKey: analysisModeKey,
   362→                        onShowCoachMarks: isCoachMarksVisible
   363→                            ? null
   364→                            : () {
   365→                                isShowingCoachMarks.value = true;
   366→                                RecordingCoachMarks.show(
   367→                                  context: context,
   368→                                  targets: RecordingCoachMarkTargets(
   369→                                    recordButtonKey: recordButtonKey,
   370→                                    analysisModeKey: analysisModeKey,
   371→                                    focusButtonKey: focusButtonKey,
   372→                                  ),
   373→                                  onFinish: () {
   374→                                    isShowingCoachMarks.value = false;
   375→                                  },
   376→                                  launchTutorialVideoUrl:
   377→                                      launchTutorialVideoUrl,
   378→                                );
   379→                              },
   380→                      );
   381→                    },
   382→                  ),
   383→                  // Latest analysis result card
   384→                  HookBuilder(
   385→                    builder: (context) {
   386→                      final isVisible =
   387→                          useValueListenable(isLatestAnalysisResultCardVisible);
   388→                      final recording = useValueListenable(isRecording);
   389→                      return Visibility(
   390→                        maintainState: true,
   391→                        visible: isVisible && !recording,
   392→                        child: LatestAnalysisResultCard(
   393→                          sessionId: sessionId,
   394→                          teamId: teamId,
   395→                          orientation: currentOrientation,
   396→                        ),
   397→                      );
   398→                    },
   399→                  ),
   400→                  // Configuration container
   401→                  Expanded(
   402→                    child: ConfigurationContainer(
   403→                      key: configurationKey,
   404→                      isRecording: isRecording,
   405→                      recordingTimerCount: recordingTimerCount,
   406→                      orientation: currentOrientation,
   407→                      selectedDisplayType: selected,
   408→                    ),
   409→                  ),
   410→                  // Control panel
   411→                  HookBuilder(
   412→                    builder: (context) {
   413→                      final showingCoachMarks =
   414→                          useValueListenable(isShowingCoachMarks);
   415→                      return GestureDetector(
   416→                        behavior: HitTestBehavior.opaque,
   417→                        onTap: () {},
   418→                        child: ControlPanel(
   419→                          orientation: currentOrientation,
   420→                          selected: selected,
   421→                          isRecording: isRecording,
   422→                          recordButtonKey: recordButtonKey,
   423→                          focusButtonKey: focusButtonKey,
   424→                          analysisModeKey: analysisModeKey,
   425→                          isButtonDisabled: showingCoachMarks,
   426→                          onTapRecordingButton: () => tapRecordingButton(
   427→                            context: context,
   428→                            ref: ref,
   429→                            isRecording: isRecording,
   430→                            currentOrientation: currentOrientation,
   431→                            recordingTimerCount: recordingTimerCount,
   432→                            recordingTimer: recordingTimer,
   433→                          ),
   434→                        ),
   435→                      );
   436→                    },
   437→                  ),
   438→                ],
   439→              ),
   440→            ),
   441→          ),
   442→        ),
   443→        // For snackbar display
   444→        const _TranslucentPointer(
   445→          child: Scaffold(backgroundColor: Colors.transparent),
   446→        ),
   447→      ],
   448→    );
   449→  }
   450→
   451→  Future<void> startRecording({
   452→    required BuildContext context,
   453→    required WidgetRef ref,
   454→    required ValueNotifier<NativeDeviceOrientation> currentOrientation,
   455→    required ValueNotifier<int> recordingTimerCount,
   456→    required ValueNotifier<bool> isRecording,
   457→    required ObjectRef<Timer?> recordingTimer,
   458→  }) async {
   459→    await ref.read(cameraControllerProvider.notifier).startRecording();
   460→
   461→    recordingTimerCount.value = 0;
   462→    recordingTimer.value = Timer.periodic(
   463→      const Duration(milliseconds: 1000),
   464→      (Timer timer) {
   465→        recordingTimerCount.value += 1;
   466→
   467→        final analysisType = ref.watch(
   468→          cameraControllerProvider.select((value) => value.analysisType),
   469→        );
   470→
   471→        final threshold = [
   472→          AnalysisType.pitchingAll,
   473→          AnalysisType.hittingAll,
   474→          AnalysisType.both
   475→        ].contains(analysisType)
   476→            // dev では 最大で 60 分まで撮影可能にする
   477→            ? isDev
   478→                ? 3600
   479→                : 120
   480→            : 10;
   481→        if (recordingTimerCount.value >= threshold) {
   482→          stopRecording(
   483→            context: context,
   484→            ref: ref,
   485→            recordingTimerCount: recordingTimerCount,
   486→            isRecording: isRecording,
   487→            recordingTimer: recordingTimer,
   488→            currentOrientation: currentOrientation,
   489→          );
   490→        }
   491→      },
   492→    );
   493→
   494→    isRecording.value = true;
   495→  }
   496→
   497→  Future<void> stopRecording({
   498→    required BuildContext context,
   499→    required WidgetRef ref,
   500→    required ValueNotifier<int> recordingTimerCount,
   501→    required ValueNotifier<bool> isRecording,
   502→    required ObjectRef<Timer?> recordingTimer,
   503→    required ValueNotifier<NativeDeviceOrientation> currentOrientation,
   504→  }) async {
   505→    recordingTimer.value!.cancel();
   506→    recordingTimer.value = null;
   507→
   508→    // NOTE: _cameraController.stopRecording causes a delay to save a video file.
   509→
   510→    // NOTE: Use `listenProviderWithLoadingDialogAndSnackbar` normally to show a loading dialog.
   511→    // But it is difficult to use the method for only a specific method of a provider.
   512→    final dialog = showLoadingDialog(context: context);
   513→    final recordedVideoData = await ref
   514→        .read(cameraControllerProvider.notifier)
   515→        .stopRecordingAndSaveToLocalStorage();
   516→    if (context.mounted) {
   517→      await popLoadingDialog(context: context, dialog: dialog);
   518→    }
   519→
   520→    ref.read(uploadQueueProvider).addUploadTask(recordedVideoData);
   521→
   522→    ScreenOrientation.setDefault();
   523→    recordingTimerCount.value = 0;
   524→    isRecording.value = false;
   525→  }
   526→
   527→  Future<void> tapRecordingButton({
   528→    required BuildContext context,
   529→    required WidgetRef ref,
   530→    required ValueNotifier<bool> isRecording,
   531→    required ValueNotifier<NativeDeviceOrientation> currentOrientation,
   532→    required ValueNotifier<int> recordingTimerCount,
   533→    required ObjectRef<Timer?> recordingTimer,
   534→  }) async {
   535→    if (isRecording.value) {
   536→      await stopRecording(
   537→        context: context,
   538→        ref: ref,
   539→        recordingTimerCount: recordingTimerCount,
   540→        isRecording: isRecording,
   541→        recordingTimer: recordingTimer,
   542→        currentOrientation: currentOrientation,
   543→      );
   544→    } else {
   545→      await startRecording(
   546→        context: context,
   547→        ref: ref,
   548→        currentOrientation: currentOrientation,
   549→        recordingTimerCount: recordingTimerCount,
   550→        recordingTimer: recordingTimer,
   551→        isRecording: isRecording,
   552→      );
   553→    }
   554→  }
   555→
   556→  void _onVolumeKeyPressed({
   557→    required BuildContext context,
   558→    required WidgetRef ref,
   559→    required ValueNotifier<bool> isRecording,
   560→    required ValueNotifier<NativeDeviceOrientation> currentOrientation,
   561→    required ValueNotifier<int> recordingTimerCount,
   562→    required ObjectRef<Timer?> recordingTimer,
   563→  }) {
   564→    if (recordingTimer.value == null && isRecording.value) {
   565→      // Do not respond while loadingDialog is displayed
   566→      return;
   567→    }
   568→    tapRecordingButton(
   569→      context: context,
   570→      ref: ref,
   571→      isRecording: isRecording,
   572→      currentOrientation: currentOrientation,
   573→      recordingTimerCount: recordingTimerCount,
   574→      recordingTimer: recordingTimer,
   575→    );
   576→  }
   577→}
   578→
   579→/// Absorbs screen rotation and forces the child to always be drawn
   580→/// as if in normal Portrait orientation (portraitUp).
   581→class _OrientationAbsorber extends StatelessWidget {
   582→  final Widget child;
   583→  final ValueChanged<NativeDeviceOrientation>? onOrientationChanged;
   584→
   585→  const _OrientationAbsorber({
   586→    required this.child,
   587→    this.onOrientationChanged,
   588→  });
   589→
   590→  @override
   591→  Widget build(BuildContext context) {
   592→    return NativeDeviceOrientationReader(
   593→      builder: (context) {
   594→        final orientation = NativeDeviceOrientationReader.orientation(context);
   595→        if (onOrientationChanged != null) {
   596→          onOrientationChanged!(orientation);
   597→        }
   598→
   599→        final turns = {
   600→          NativeDeviceOrientation.unknown: 0,
   601→          NativeDeviceOrientation.portraitUp: 0,
   602→          NativeDeviceOrientation.landscapeRight: 1,
   603→          NativeDeviceOrientation.portraitDown: 2,
   604→          NativeDeviceOrientation.landscapeLeft: 3,
   605→        }[orientation]!;
   606→
   607→        final original = MediaQuery.of(context);
   608→        final modified = original.copyWith(
   609→          size: _rotateSize(original.size, turns),
   610→          padding: _rotateEdgeInsets(original.padding, turns),
   611→          viewPadding: _rotateEdgeInsets(original.viewPadding, turns),
   612→          viewInsets: _rotateEdgeInsets(original.viewInsets, turns),
   613→          systemGestureInsets:
   614→              _rotateEdgeInsets(original.systemGestureInsets, turns),
   615→        );
   616→
   617→        return RotatedBox(
   618→          quarterTurns: turns,
   619→          child: MediaQuery(
   620→            data: modified,
   621→            child: child,
   622→          ),
   623→        );
   624→      },
   625→    );
   626→  }
   627→
   628→  Size? _rotateSize(Size? src, int turns) {
   629→    if (src == null) {
   630→      return null;
   631→    }
   632→    return turns % 2 == 1 ? src.flipped : src;
   633→  }
   634→
   635→  EdgeInsets _rotateEdgeInsets(EdgeInsets src, int turns) {
   636→    switch (turns % 4) {
   637→      case 0:
   638→        return src;
   639→      case 1:
   640→        return EdgeInsets.fromLTRB(src.top, src.right, src.bottom, src.left);
   641→      case 2:
   642→        return EdgeInsets.fromLTRB(src.right, src.bottom, src.left, src.top);
   643→      default:
   644→        return EdgeInsets.fromLTRB(src.bottom, src.left, src.top, src.right);
   645→    }
   646→  }
   647→}
   648→
   649→/// Routes pointer events to the child widget as well as to
   650→/// an overlapping widget below.
   651→class _TranslucentPointer extends SingleChildRenderObjectWidget {
   652→  const _TranslucentPointer({
   653→    super.child,
   654→  });
   655→
   656→  @override
   657→  _RenderTranslucentPointer createRenderObject(BuildContext context) {
   658→    return _RenderTranslucentPointer();
   659→  }
   660→}
   661→
   662→class _RenderTranslucentPointer extends RenderProxyBox {
   663→  @override
   664→  bool hitTest(BoxHitTestResult result, {required Offset position}) {
   665→    super.hitTest(result, position: position);
   666→    return false;
   667→  }
   668→}
