   380→      // So this project leverages `permission_handler` library to handle camera permission.
   381→      final isPermissionGranted = await Permission.camera.request().isGranted;
   382→      if (!isPermissionGranted) {
   383→        _logger.w('Camera permission is not granted');
   384→        return null;
   385→      }
   386→
   387→      _logger.i('Camera permission is granted');
   388→
   389→      final cameraId = await cameraAPI.configureSession(
   390→        onVolumeKeyPressed: onVolumeKeyPressed,
   391→      );
   392→
   393→      _logger.i('Camera session configured with ID: $cameraId');
   394→
   395→      // 主要なカメラパラメータを一括取得してstateを更新
   396→      await _updateNativeParameters();
   397→
   398→      _logger.i('Camera parameters updated');
   399→
   400→      if (isIos) {
   401→        await _setPreferences();
   402→        _logger.i('Camera preferences set');
   403→      } else {
   404→        await cameraAPI.setFocusModeToAuto();
   405→        if (state.isStabilizationAvailable == true) {
   406→          await setStabilizationModeOn();
   407→        }
   408→      }
   409→
   410→      if (!_timerStarted) {
   411→        _startParamUpdateTimer();
   412→        _timerStarted = true;
   413→      }
   414→
   415→      return cameraId;
   416→    } catch (e, stacktrace) {
   417→      _logger.e('Failed to configure session', ex: e, stacktrace: stacktrace);
   418→      return null;
   419→    }
   420→  }
