   422→  Future<void> _updateNativeParameters() async {
   423→    final (
   424→      iso,
   425→      shutterSpeed,
   426→      lens,
   427→      isFocusModeAuto,
   428→      focus,
   429→      zoom,
   430→      format,
   431→      minZoom,
   432→      maxZoom,
   433→    ) = await (
   434→      getISO(),
   435→      getShutterSpeed(),
   436→      getLensIndex().then((idx) async {
   437→        final lensList = await getLensList();
   438→        if (lensList != null &&
   439→            idx != null &&
   440→            idx >= 0 &&
   441→            idx < lensList.length) {
   442→          return lensList[idx];
   443→        }
   444→        return null;
   445→      }),
   446→      isAutoFocus(),
   447→      getFocus(),
   448→      getZoom(),
   449→      getFormatIndex().then((idx) async {
   450→        final formatList = await getFormatList();
   451→        if (formatList != null &&
   452→            idx != null &&
   453→            idx >= 0 &&
   454→            idx < formatList.length) {
   455→          return formatList[idx];
   456→        }
   457→        return null;
   458→      }),
   459→      getMinZoom(),
   460→      getMaxZoom(),
   461→    ).wait;
   462→
   463→    final (
   464→      minFocus,
   465→      maxFocus,
   466→      minISO,
   467→      maxISO,
   468→      minShutterSpeed,
   469→      maxShutterSpeed,
   470→      lensList,
   471→      formatList,
   472→    ) = await (
   473→      getMinFocus(),
   474→      getMaxFocus(),
   475→      getMinISO(),
   476→      getMaxISO(),
   477→      getMinShutterSpeed(),
   478→      getMaxShutterSpeed(),
   479→      getLensList(),
   480→      getFormatList(),
   481→    ).wait;
   482→
   483→    // 追加: NativeParametersの全更新
   484→    final isStabilizationAvailable = await isStabilizationSupportedDevice();
   485→    final telephotoLensList = lensList == null
   486→        ? <Lens>[]
   487→        : lensList.where((lens) => lens.isTelephoto).toList();
   488→    final wideAngleLensList = lensList == null
   489→        ? <Lens>[]
   490→        : lensList.where((lens) => lens.isWideAngle).toList();
   491→    final isTelephotoAvailable = telephotoLensList.isNotEmpty;
   492→
   493→    final extendedZoom =
   494→        (lens != null && zoom != null && minZoom != null && maxZoom != null)
   495→            ? ExtendedZoomType.fromLensAndZoom(
   496→                currentLens: lens,
   497→                currentZoom: zoom,
   498→                minZoom: minZoom,
   499→                maxZoom: maxZoom,
   500→              )
   501→            : null;
   502→
   503→    state = state.copyWith(
   504→      minZoom: minZoom,
   505→      maxZoom: maxZoom,
   506→      minFocus: minFocus,
   507→      maxFocus: maxFocus,
   508→      minISO: minISO,
   509→      maxISO: maxISO,
   510→      minShutterSpeed: minShutterSpeed,
   511→      maxShutterSpeed: maxShutterSpeed,
   512→      lensList: lensList,
   513→      formatList: formatList,
   514→      iso: iso,
   515→      shutterSpeed: shutterSpeed,
   516→      lens: lens,
   517→      isFocusModeAuto: isFocusModeAuto,
   518→      focus: focus,
   519→      zoom: zoom,
   520→      extendedZoom: extendedZoom,
   521→      format: format,
   522→      // 追加分
   523→      isStabilizationAvailable: isStabilizationAvailable,
   524→      telephotoLensList: telephotoLensList,
   525→      wideAngleLensList: wideAngleLensList,
   526→      isTelephotoAvailable: isTelephotoAvailable,
   527→    );
   528→  }
