   652→  Future<String?> startRecording() async {
   653→    try {
   654→      _isAutoExposure = await isAutoExposure();
   655→      await tearDownAutoExposureObserver();
   656→
   657→      if (_currentSession == null) {
   658→        throw Exception();
   659→      }
