   661→      final accelerationController =
   662→          AccelerationController.getSingletonObject();
   663→      final orientation = await NativeDeviceOrientationCommunicator()
   664→          .orientation(useSensor: false);
   665→      accelerationController.setOrientation(orientation);
   666→
   667→      final now = DateTime.now(); // NOTE: It's local time
   668→      final fileName = now
   669→          .toString()
   670→          .replaceAll(' ', '_'); // extension is decided by native side.
   671→      await Directory(_currentSession!.directory).create(recursive: true);
   672→      final filePath = join(
   673→          _currentSession!.directory, _sanitizeRecordingFileName(fileName));
   674→
   675→      accelerationController.reset();
   676→      accelerationController.start();
   677→
   678→      _currentSession!.recordingFilePath =
   679→          await cameraAPI.startRecording(filePath);
   680→      return _currentSession!.recordingFilePath;
   681→    } catch (e, stacktrace) {
   682→      _logger.e('Failed to start recording', ex: e, stacktrace: stacktrace);
   683→      rethrow;
