   761→
   762→      final deviceInfo = DeviceInfoPlugin();
   763→      final device = platform.isAndroid
   764→          ? (await deviceInfo.androidInfo).model
   765→          : (await deviceInfo.iosInfo).utsname.fixedProductName();
   766→
   767→      final localVideoListController =
   768→          ref.read(localVideoListControllerProvider.notifier);
   769→      LocalVideoData? newData;
   770→
   771→      final teamId = profileStorage.getTeamId()!;
   772→
   773→      // NOTE: The method cameraAPI.stopRecording returns before completes saving a video file.
