   775→      await Future.delayed(const Duration(milliseconds: 500), () async {
   776→        newData = await localVideoListController.addFile(
   777→          sessionId: _currentSession!.sessionId,
   778→          teamId: teamId,
   779→          filePath: _currentSession!.recordingFilePath!,
   780→          analyzeType: state.analysisType.value,
   781→          focalLengthIn35mmEquivalent: null,
   782→          longsideAngleOfView: longsideAngleOfView!,
   783→          accX: accX,
   784→          accY: accY,
   785→          accZ: accZ,
   786→          lens: lens?.description,
   787→          cameraMode:
   788→              '${extendedZoomType == null ? '-' : extendedZoomType.name}+${state.cameraMode == null ? '-' : state.cameraMode!.name}${_isAutoExposure ? ' (AE)' : ''}',
   789→          focus: focus,
   790→          isAutoFocus: isAutoFocus,
   791→          zoom: zoom,
   792→          iso: iso,
   793→          shutterSpeed: shutterSpeed,
   794→          device: device,
   795→        );
   796→      });
   797→
   798→      _currentSession!.recordingFilePath = null;
   799→
   800→      return newData!;
   801→    } catch (e, stacktrace) {
