  1017→  /// シンプルに「一番良いフルHDフォーマット」を返す
  1018→  /// 1. フルHDかつ120FPS未満だけ抽出
  1019→  /// 2. 最大FPSを求める
  1020→  /// 3. 非HDRかつ非Binnedを最優先
  1021→  /// 4. 非Binnedを次点で
  1022→  /// 5. それもなければ最初のもの
  1023→  Format? selectBestFullHDFormat(List<Format> formatList) {
  1024→    // 1. フルHDかつ120FPS未満だけ抽出
  1025→    final fullHDFormats =
  1026→        formatList.where((f) => f.isFullHD && f.fps < 120).toList();
  1027→
  1028→    if (fullHDFormats.isEmpty) return null;
  1029→
  1030→    // 2. 最大FPSを求める
  1031→    final maxFps =
  1032→        fullHDFormats.map((f) => f.fps).reduce((a, b) => a > b ? a : b);
  1033→    final maxFpsFormats = fullHDFormats.where((f) => f.fps == maxFps).toList();
  1034→
  1035→    // 3. 非HDRかつ非Binnedを最優先
  1036→    final best = maxFpsFormats.where((f) => !f.hdr && !f.binned);
  1037→    if (best.isNotEmpty) return best.first;
  1038→
  1039→    // 4. 非Binnedを次点で
  1040→    final nonBinned = maxFpsFormats.where((f) => !f.binned);
  1041→    if (nonBinned.isNotEmpty) return nonBinned.first;
  1042→
  1043→    // 5. それもなければ最初のもの
  1044→    return maxFpsFormats.first;
  1045→  }
