  1200→  Future<void> setExtendedZoomType(ExtendedZoomType extendedZoomType) async {
  1201→    try {
  1202→      int targetLensIndex;
  1203→      double targetZoom;
  1204→
  1205→      switch (extendedZoomType) {
  1206→        case ExtendedZoomType.superZoom:
  1207→          // Telephoto × max zoom
  1208→          if (state.telephotoLensList.isEmpty) {
  1209→            throw Exception('Telephoto lens not available for superZoom');
  1210→          }
  1211→          targetLensIndex = state.telephotoLensList.first.index;
  1212→          targetZoom = state.maxZoom ?? CameraState.defaultMaxZoom;
  1213→          break;
  1214→        case ExtendedZoomType.zoom:
  1215→          // Telephoto × min zoom
  1216→          if (state.telephotoLensList.isEmpty) {
  1217→            throw Exception('Telephoto lens not available for zoom');
  1218→          }
  1219→          targetLensIndex = state.telephotoLensList.first.index;
  1220→          targetZoom = state.minZoom ?? CameraState.defaultMinZoom;
  1221→          break;
  1222→        case ExtendedZoomType.wide:
  1223→          // WideAngle × max zoom
  1224→          if (state.wideAngleLensList.isEmpty) {
  1225→            throw Exception('WideAngle lens not available for wide');
  1226→          }
  1227→          targetLensIndex = state.wideAngleLensList.first.index;
  1228→          targetZoom = state.maxZoom ?? CameraState.defaultMaxZoom;
  1229→          break;
  1230→        case ExtendedZoomType.superWide:
  1231→          // WideAngle × min zoom
  1232→          if (state.wideAngleLensList.isEmpty) {
  1233→            throw Exception('WideAngle lens not available for superWide');
  1234→          }
  1235→          targetLensIndex = state.wideAngleLensList.first.index;
  1236→          targetZoom = state.minZoom ?? CameraState.defaultMinZoom;
  1237→          break;
  1238→      }
  1239→
  1240→      // Save to profileStorage
  1241→      profileStorage.setCameraExtendedZoomType(extendedZoomType);
  1242→
  1243→      // Apply settings (lens first, then zoom)
  1244→      await setLensIndex(targetLensIndex);
  1245→      await setZoom(targetZoom);
  1246→
  1247→      // Update state
  1248→      state = state.copyWith(extendedZoom: extendedZoomType);
  1249→    } catch (e, stacktrace) {
  1250→      _logger.e('Failed to set extended zoom type',
  1251→          ex: e, stacktrace: stacktrace);
  1252→      rethrow;
  1253→    }
  1254→  }
