  1265→      // Stabilization mode is sometimes turned off by iOS when it changes its lens.
  1266→      if (state.isStabilizationAvailable == true) {
  1267→        await setStabilizationModeOn();
  1268→      }
  1269→
  1270→      setUpAutoExposureObserver();
  1271→
