  /// シンプルに「一番良いフルHDフォーマット」を返す
  /// 1. フルHDかつ120FPS未満だけ抽出
  /// 2. 最大FPSを求める
  /// 3. 非HDRかつ非Binnedを最優先
  /// 4. 非Binnedを次点で
  /// 5. それもなければ最初のもの
  Format? selectBestFullHDFormat(List<Format> formatList) {
    // 1. フルHDかつ120FPS未満だけ抽出
    final fullHDFormats =
        formatList.where((f) => f.isFullHD && f.fps < 120).toList();

    if (fullHDFormats.isEmpty) return null;

    // 2. 最大FPSを求める
    final maxFps =
        fullHDFormats.map((f) => f.fps).reduce((a, b) => a > b ? a : b);
    final maxFpsFormats = fullHDFormats.where((f) => f.fps == maxFps).toList();

    // 3. 非HDRかつ非Binnedを最優先
    final best = maxFpsFormats.where((f) => !f.hdr && !f.binned);
    if (best.isNotEmpty) return best.first;

    // 4. 非Binnedを次点で
    final nonBinned = maxFpsFormats.where((f) => !f.binned);
    if (nonBinned.isNotEmpty) return nonBinned.first;

    // 5. それもなければ最初のもの
    return maxFpsFormats.first;
  }

