@protected
Future<T> upload<T>({
  String method = 'POST',
  required String url,
  Map<String, dynamic>? queryParameters,
  Map<String, dynamic>? headers,
  T Function(Map<String, dynamic>)? responseMapper,
  void Function(double)? onProgress,

  /// A Dio-compatible object for canceling requests
  CancelToken? cancelToken,

  /// Multipart fields **excluding** the file to be uploaded
  Map<String, dynamic>? data,

  /// The mime type of the file to be uploaded
  String? contentType,

  /// The name of the multipart field that stores the file to be uploaded
  required String fileField,

  /// The path of the file to be uploaded
  required String filePath,
}) async {
  final methodFc = _fc.category('UL');

  final fileName = basename(filePath);
  final fileDir = dirname(filePath);

  final task = UploadTask(
    httpRequestMethod: method,
    url: appendQueryParameters(url, queryParameters),
    headers: headers?.map((k, v) => MapEntry(k, v.toString())),
    filename: fileName,
    directory: fileDir,
    baseDirectory: BaseDirectory.root,
    fileField: fileField,
    fields: data?.map((k, v) => MapEntry(k.toString(), v.toString())),
  );
  final responseFuture = _downloader.upload(task, onProgress: onProgress);

  return await _processResponse(
    fc: methodFc,
    request: task,
    responseFuture: responseFuture,
    responseMapper: responseMapper,
    cancelToken: cancelToken,
  );
}

